import React, { useState } from 'react';

const allProjects = [
  [
    { href: 'https://dimacalingtechnicaldocumentation.vercel.app/', img: '/images/technicaldocument.png', title: 'Technical Document Web Page', desc: 'A website in the form of a technical document.' },
    { href: 'https://dimacalingsurvey.vercel.app/', img: '/images/survey.png', title: 'Customer Satisfaction Survey', desc: 'A form that intakes customer feedback.' },
    { href: 'https://dimacalingtributepage.vercel.app/', img: '/images/tribute.png', title: 'Tribute Page', desc: 'A page that shows gratitude to my brother.' },
  ],
  [
    { href: 'https://dimacalingportfolio.vercel.app/', img: '/images/portfolio.png', title: 'Personal Portfolio', desc: 'A page showcasing my past works.' },
    { href: 'https://onlineportfoliocc1.vercel.app/', img: '/images/groupwebsite.png', title: 'Group Portfolio', desc: 'Simple web page we made in first-year of university.' },
  ],
];

const Projects = () => {
  const [current, setCurrent] = useState(0);
  const [hoveredCard, setHoveredCard] = useState(null);

  const prev = () => setCurrent((c) => (c === 0 ? allProjects.length - 1 : c - 1));
  const next = () => setCurrent((c) => (c === allProjects.length - 1 ? 0 : c + 1));

  return (
    <section
      id="Projects"
      className="flex flex-col items-center px-10 pt-24 pb-16"
      style={{
  background: 'linear-gradient(180deg, #0b1f3f 0%, #0f0f0f 100%)',
  fontFamily: "'Orbitron', sans-serif",
}}
    >
      <h1 className="font-bold text-4xl text-white text-center mb-12">
        My Projects
      </h1>

      <div className="relative w-full max-w-4xl">
        <div className="flex justify-center gap-6 flex-wrap">
          {allProjects[current].map((project, i) => {
            const isHov = hoveredCard === i;

            return (
              <a
                key={i}
                href={project.href}
                target="_blank"
                rel="noreferrer"
                className="no-underline"
              >
                <div
                  className="rounded-xl overflow-hidden transition-all duration-300"
                  style={{
                    width: '220px',
                    background: '#fff', // ✅ WHITE CARD
                    borderLeft: '4px solid #0d6efd',
                    boxShadow: isHov
                      ? '0 8px 25px rgba(0,0,0,0.25)'
                      : '0 4px 15px rgba(0,0,0,0.15)',
                    transform: isHov ? 'translateY(-8px)' : 'translateY(0)',
                  }}
                  onMouseEnter={() => setHoveredCard(i)}
                  onMouseLeave={() => setHoveredCard(null)}
                >
                  <img
                    src={project.img}
                    alt={project.title}
                    className="w-full object-cover"
                    style={{ height: '150px' }}
                  />

                  <div className="p-4 text-center">
                    <h5 className="font-bold text-sm text-black">
                      {project.title}
                    </h5>

                    <p className="text-xs text-gray-600 mt-1">
                      {project.desc}
                    </p>
                  </div>
                </div>
              </a>
            );
          })}
        </div>

        {/* NAV BUTTONS */}
        <button
          onClick={prev}
          className="absolute -left-6 top-0 bottom-0 my-auto w-10 h-10 rounded-full text-white text-xl font-bold flex items-center justify-center"
          style={{
            background: '#0d6efd',
            cursor: 'pointer',
          }}
        >
          {'<'}
        </button>

        <button
          onClick={next}
          className="absolute -right-6 top-0 bottom-0 my-auto w-10 h-10 rounded-full text-white text-xl font-bold flex items-center justify-center"
          style={{
            background: '#0d6efd',
            cursor: 'pointer',
          }}
        >
          {'>'}
        </button>
      </div>

      {/* DOTS */}
      <div className="flex gap-3 mt-8">
        {allProjects.map((_, i) => (
          <button
            key={i}
            onClick={() => setCurrent(i)}
            className="rounded-full transition-all"
            style={{
              width: i === current ? '24px' : '10px',
              height: '10px',
              background: i === current ? '#0d6efd' : '#555',
            }}
          />
        ))}
      </div>
    </section>
  );
};

export default Projects;
